// sqlite_filtered_test.go — TDD tests for the *GA helpers added in
// internal/sqlite/sqlite_filtered.go (Plan 02 Task 1 of the race-broadcaster).
//
// These helpers MUST behave exactly like their unsuffixed siblings except
// they restrict results to rounds whose RoundCode starts with "GA"
// (i.e. rounds generated by cmd/race-generator, not captured from DS).
//
// The tests also include a regression check on GamesWindow to assert that
// the unsuffixed function continues to return ALL rounds (no behavioural
// drift from adding the new helpers).
package sqlite

import (
	"fmt"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"vg-racegen/internal/models"
)

// toRoundCodeNumeric builds a synthetic numeric round code like
// "541_105_20260520_120000_001" (the prefix race-broadcaster must filter OUT).
func toRoundCodeNumeric(betoffer int, ts time.Time, n int) string {
	return fmt.Sprintf("%d_%d_%s_%03d", betoffer, 105, ts.UTC().Format("20060102_150405"), n)
}

// toRoundCodeGA builds a synthetic generated round code like
// "GA541_105_20260520_120000_001" (the prefix that *GA helpers must keep).
func toRoundCodeGA(betoffer int, ts time.Time, n int) string {
	return "GA" + toRoundCodeNumeric(betoffer, ts, n)
}

// seedMixedRounds inserts 3 DS-style rounds (numeric prefix, finished) and
// 3 GA-style rounds (GA prefix, open) for a given betoffer so the helpers
// can be exercised against a realistic mix.
func seedMixedRounds(t *testing.T, betoffer int) {
	t.Helper()
	now := time.Now().UTC().Truncate(time.Second)

	mk := func(code, gameType string, ts time.Time, status string) {
		var finishedAt *string
		if status == "F" {
			s := ts.Add(45 * time.Second).Format(time.RFC3339)
			finishedAt = &s
		}
		gr := &models.GameRound{
			RoundCode:    code,
			GameTypeID:   betoffer,
			GameType:     gameType,
			Status:       status,
			VideoStartDt: ts.Format("2006-01-02 15:04:05"),
			VideoEndDt:   ts.Add(45 * time.Second).Format("2006-01-02 15:04:05"),
			CreatedAt:    ts.Format(time.RFC3339),
			FinishedAt:   finishedAt,
		}
		if _, err := UpsertGameRound(gr); err != nil {
			t.Fatalf("upsert %s: %v", code, err)
		}
	}

	// 3 DS-captured rounds in the past, all finished.
	for i := 0; i < 3; i++ {
		ts := now.Add(time.Duration(-i-10) * time.Minute)
		mk(toRoundCodeNumeric(betoffer, ts, i), "dog8", ts, "F")
	}
	// 3 GA-generated rounds in the future, all open.
	for i := 0; i < 3; i++ {
		ts := now.Add(time.Duration(i+1) * time.Minute)
		mk(toRoundCodeGA(betoffer, ts, i), "dog8", ts, "O")
	}
}

// seedMixedRoundsWithFinishedGA additionally inserts 2 GA rounds that are
// already finished so RecentResultsGA / GamesWindowGA history side can find
// them.
func seedMixedRoundsWithFinishedGA(t *testing.T, betoffer int) {
	t.Helper()
	seedMixedRounds(t, betoffer)

	now := time.Now().UTC().Truncate(time.Second)
	mk := func(code string, ts time.Time) {
		finished := ts.Add(45 * time.Second).Format(time.RFC3339)
		gr := &models.GameRound{
			RoundCode:    code,
			GameTypeID:   betoffer,
			GameType:     "dog8",
			Status:       "F",
			VideoStartDt: ts.Format("2006-01-02 15:04:05"),
			VideoEndDt:   ts.Add(45 * time.Second).Format("2006-01-02 15:04:05"),
			CreatedAt:    ts.Format(time.RFC3339),
			FinishedAt:   &finished,
		}
		if _, err := UpsertGameRound(gr); err != nil {
			t.Fatalf("upsert %s: %v", code, err)
		}
	}
	for i := 0; i < 2; i++ {
		// Use a wider offset so codes don't collide with the open GA seeds.
		ts := now.Add(time.Duration(-i-30) * time.Minute)
		mk(toRoundCodeGA(betoffer, ts, 100+i), ts)
	}
}

func TestGamesWindowGA_OnlyReturnsGARounds(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_window.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithFinishedGA(t, betoffer)

	rounds, err := GamesWindowGA(betoffer, 10, 10)
	if err != nil {
		t.Fatalf("GamesWindowGA: %v", err)
	}
	// 2 finished GA + 3 open GA = 5.
	if len(rounds) != 5 {
		t.Fatalf("GamesWindowGA len=%d, want 5; rounds=%v", len(rounds), roundCodes(rounds))
	}
	for _, r := range rounds {
		if len(r.RoundCode) < 2 || r.RoundCode[:2] != "GA" {
			t.Fatalf("non-GA round leaked: %s", r.RoundCode)
		}
	}
}

// TestGamesWindowGA_AllFinishedStatus reproduces the production data shape:
// the race-generator persists EVERY GA round with Status='F' (outcome baked
// in at generation time), so the past/future split must come from VideoEndDt
// vs. now, NOT from Status. A Status-based split would put every round in
// the history bucket (Status='F') and leave the future bucket empty, so the
// webview would receive an all-past (or, with DESC+LIMIT, all-furthest-future)
// window with no playable "now" round → err_setup. This test seeds rounds
// straddling now, all Status='F', and asserts the window straddles correctly.
func TestGamesWindowGA_AllFinishedStatus(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_allF.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	now := time.Now().UTC().Truncate(time.Second)
	mk := func(ts time.Time, n int) {
		finished := ts.Add(45 * time.Second).Format(time.RFC3339)
		gr := &models.GameRound{
			RoundCode:    toRoundCodeGA(betoffer, ts, n),
			GameTypeID:   betoffer,
			GameType:     "dog8",
			Status:       "F", // every GA round is persisted finished
			VideoStartDt: ts.Format("2006-01-02 15:04:05"),
			VideoEndDt:   ts.Add(45 * time.Second).Format("2006-01-02 15:04:05"),
			CreatedAt:    ts.Format(time.RFC3339),
			FinishedAt:   &finished,
		}
		if _, err := UpsertGameRound(gr); err != nil {
			t.Fatalf("upsert: %v", err)
		}
	}
	// 6 past rounds (ended before now) + the in-progress round (started 10s
	// ago, ends in 35s) + 5 strictly-future rounds.
	for i := 1; i <= 6; i++ {
		mk(now.Add(time.Duration(-i)*4*time.Minute), i)
	}
	mk(now.Add(-10*time.Second), 100) // in-progress: VideoEndDt > now
	for i := 1; i <= 5; i++ {
		mk(now.Add(time.Duration(i)*4*time.Minute), 200+i)
	}

	rounds, err := GamesWindowGA(betoffer, 8, 10)
	if err != nil {
		t.Fatalf("GamesWindowGA: %v", err)
	}
	// history = VideoEndDt<=now (the 6 past) ; future = VideoEndDt>now (the
	// in-progress + 5 strictly-future = 6). Total 12.
	if len(rounds) != 12 {
		t.Fatalf("len=%d, want 12; rounds=%v", len(rounds), roundCodes(rounds))
	}
	// The window must be ASC by VideoStartDt and straddle now: at least one
	// round before now and at least one round whose video has not yet ended.
	var beforeNow, openNow int
	nowStr := now.Format("2006-01-02 15:04:05")
	for _, r := range rounds {
		if r.VideoEndDt <= nowStr {
			beforeNow++
		} else {
			openNow++
		}
	}
	if beforeNow == 0 || openNow == 0 {
		t.Fatalf("window does not straddle now: before=%d open=%d", beforeNow, openNow)
	}
	if openNow != 6 {
		t.Errorf("open/future side = %d, want 6 (in-progress + 5 future)", openNow)
	}
}

