func TestCurrentGameGA_ErrorsWhenNoGAOpen(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_current_empty.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	// Seed ONLY DS rounds (no GA at all) so CurrentGameGA should error out
	// even though CurrentGame would have returned something.
	now := time.Now().UTC().Truncate(time.Second)
	for i := 0; i < 3; i++ {
		ts := now.Add(time.Duration(i+1) * time.Minute)
		gr := &models.GameRound{
			RoundCode:    toRoundCodeNumeric(betoffer, ts, i),
			GameTypeID:   betoffer,
			GameType:     "dog8",
			Status:       "O",
			VideoStartDt: ts.Format("2006-01-02 15:04:05"),
			VideoEndDt:   ts.Add(45 * time.Second).Format("2006-01-02 15:04:05"),
			CreatedAt:    ts.Format(time.RFC3339),
		}
		if _, err := UpsertGameRound(gr); err != nil {
			t.Fatalf("seed DS: %v", err)
		}
	}

	if _, err := CurrentGameGA(betoffer); err == nil {
		t.Fatal("CurrentGameGA: want error when only DS rounds exist, got nil")
	}
	// CurrentGame (unfiltered) must still succeed — proves the filter is
	// scoped to the new helper and didn't alter the original.
	if _, err := CurrentGame(betoffer); err != nil {
		t.Fatalf("CurrentGame (unfiltered) regressed: %v", err)
	}
}

