// TestOriginalGamesWindowReturnsAll is the regression test ensuring that
// adding the *GA helpers did NOT alter the behaviour of the un-suffixed
// GamesWindow. It must still return BOTH GA and numeric rounds.
func TestOriginalGamesWindowReturnsAll(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "all_window.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithFinishedGA(t, betoffer)

	rounds, err := GamesWindow(betoffer, 10, 10)
	if err != nil {
		t.Fatalf("GamesWindow: %v", err)
	}
	// 3 DS finished + 2 GA finished + 3 GA open = 8.
	if len(rounds) != 8 {
		t.Fatalf("GamesWindow len=%d, want 8 (all rounds); rounds=%v", len(rounds), roundCodes(rounds))
	}

	hasNumeric, hasGA := false, false
	for _, r := range rounds {
		if len(r.RoundCode) >= 2 && r.RoundCode[:2] == "GA" {
			hasGA = true
		} else {
			hasNumeric = true
		}
	}
	if !hasGA || !hasNumeric {
		t.Fatalf("GamesWindow regressed: want both GA and numeric; hasGA=%v hasNumeric=%v", hasGA, hasNumeric)
	}
}

func roundCodes(rs []*models.GameRound) []string {
	out := make([]string, len(rs))
	for i, r := range rs {
		out[i] = r.RoundCode
	}
	return out
}

// =====================================================================
// Plan 04 DS-ISOLATION Task 1 — tests for the *DS mirror helpers.
//
// These tests assert the inverse contract of the *GA helpers above: the
// *DS family must filter OUT rounds whose RoundCode starts with "GA"
// (i.e. only DS-captured vendor rounds reach the ws-server). They mirror
// the seeding pattern of the *GA tests (seedMixedRounds /
// seedMixedRoundsWithFinishedGA) and add a couple of small extensions
// (seedMixedFutures, seedMixedRoundsWithResults, recovery helpers for
// the seeded codes) that the *GA tests did not need.
// =====================================================================

// seedMixedFutures inserts 3 DS-style rounds AND 3 GA-style rounds all in
// the FUTURE and OPEN. This is what UpcomingGamesDS expects to see (the
// existing seedMixedRounds has DS rounds in the past + finished, so
// UpcomingGamesDS would return nothing without this variant).
func seedMixedFutures(t *testing.T, betoffer int) {
	t.Helper()
	now := time.Now().UTC().Truncate(time.Second)
	mk := func(code string, ts time.Time) {
		gr := &models.GameRound{
			RoundCode:    code,
			GameTypeID:   betoffer,
			GameType:     "dog8",
			Status:       "O",
			VideoStartDt: ts.Format("2006-01-02 15:04:05"),
			VideoEndDt:   ts.Add(45 * time.Second).Format("2006-01-02 15:04:05"),
			CreatedAt:    ts.Format(time.RFC3339),
		}
		if _, err := UpsertGameRound(gr); err != nil {
			t.Fatalf("upsert %s: %v", code, err)
		}
	}
	// 3 DS open in future (offset 1..3 min).
	for i := 0; i < 3; i++ {
		ts := now.Add(time.Duration(i+1) * time.Minute)
		mk(toRoundCodeNumeric(betoffer, ts, i), ts)
	}
	// 3 GA open in future (offset 10..12 min so codes don't collide).
	for i := 0; i < 3; i++ {
		ts := now.Add(time.Duration(i+10) * time.Minute)
		mk(toRoundCodeGA(betoffer, ts, i), ts)
	}
}

// seedMixedRoundsWithResults builds on seedMixedRounds (3 DS finished + 3
// GA open) and additionally:
//   - upserts 2 GA FINISHED rounds (so RecentResultsDS must reject them),
//   - writes GameResults rows for every finished round (DS + GA) so the
//     StatsHistoryDS history rows have non-empty position arrays.
func seedMixedRoundsWithResults(t *testing.T, betoffer int) {
	t.Helper()
	seedMixedRoundsWithFinishedGA(t, betoffer)

	// Find every finished round and write a deterministic result for it.
	rows, err := db.Query(
		`SELECT RoundCode FROM GameRounds WHERE GameTypeId=? AND Status='F'`,
		betoffer,
	)
	if err != nil {
		t.Fatalf("list finished: %v", err)
	}
	defer rows.Close()
	var codes []string
	for rows.Next() {
		var c string
		if err := rows.Scan(&c); err != nil {
			t.Fatalf("scan finished: %v", err)
		}
		codes = append(codes, c)
	}
	for _, c := range codes {
		ft := 30.5
		results := []models.GameResult{
			{Position: 1, RunnerNumber: 7, FinishTime: &ft},
			{Position: 2, RunnerNumber: 3, FinishTime: nil},
		}
		if err := SaveResult(c, results); err != nil {
			t.Fatalf("SaveResult %s: %v", c, err)
		}
	}
}

// allSeededCodes returns every RoundCode currently in the GameRounds
// table for the given betoffer, in insertion-agnostic order. Used by the
// caller-side filter tests so they don't need to rebuild the synthetic
// codes the seed helpers produced.
func allSeededCodes(t *testing.T, betoffer int) []string {
	t.Helper()
	rows, err := db.Query(
		`SELECT RoundCode FROM GameRounds WHERE GameTypeId=?`,
		betoffer,
	)
	if err != nil {
		t.Fatalf("allSeededCodes query: %v", err)
	}
	defer rows.Close()
	var out []string
	for rows.Next() {
		var c string
		if err := rows.Scan(&c); err != nil {
			t.Fatalf("allSeededCodes scan: %v", err)
		}
		out = append(out, c)
	}
	return out
}

// firstDSCode returns one RoundCode that does NOT start with "GA".
func firstDSCode(t *testing.T, betoffer int) string {
	t.Helper()
	for _, c := range allSeededCodes(t, betoffer) {
		if !strings.HasPrefix(c, "GA") {
			return c
		}
	}
	t.Fatal("firstDSCode: no DS round seeded")
	return ""
}

// firstGACode returns one RoundCode that starts with "GA".
func firstGACode(t *testing.T, betoffer int) string {
	t.Helper()
	for _, c := range allSeededCodes(t, betoffer) {
		if strings.HasPrefix(c, "GA") {
			return c
		}
	}
	t.Fatal("firstGACode: no GA round seeded")
	return ""
}

func TestGamesWindowDS_FiltersGA(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ds_window.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithFinishedGA(t, betoffer) // 3 DS finished + 2 GA finished + 3 GA open

	rounds, err := GamesWindowDS(betoffer, 10, 10)
	if err != nil {
		t.Fatalf("GamesWindowDS: %v", err)
	}
	// Only the 3 DS finished rounds should survive (no DS open seeded).
	if len(rounds) != 3 {
		t.Fatalf("GamesWindowDS len=%d, want 3 DS-only; rounds=%v", len(rounds), roundCodes(rounds))
	}
	for _, r := range rounds {
		if strings.HasPrefix(r.RoundCode, "GA") {
			t.Fatalf("GA round leaked into DS path: %s", r.RoundCode)
		}
	}
}

