func TestGameByRoundCodeDS_ReturnsNilForGA(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ds_by_code.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRounds(t, betoffer)

	dsCode := firstDSCode(t, betoffer)
	r, err := GameByRoundCodeDS(dsCode)
	if err != nil || r == nil {
		t.Fatalf("expected DS round, got err=%v round=%v", err, r)
	}
	if r.RoundCode != dsCode {
		t.Fatalf("GameByRoundCodeDS got %s, want %s", r.RoundCode, dsCode)
	}

	gaCode := firstGACode(t, betoffer)
	r2, err := GameByRoundCodeDS(gaCode)
	if err != nil {
		t.Fatalf("expected no error for GA code, got %v", err)
	}
	if r2 != nil {
		t.Fatalf("expected nil for GA code, got %v", r2)
	}
}

func TestGamesByRoundCodesGA_FiltersDSPrefix(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_by_codes.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRounds(t, betoffer) // 3 DS finished + 3 GA open = 6 codes

	codes := allSeededCodes(t, betoffer)
	if len(codes) != 6 {
		t.Fatalf("seeded codes len=%d, want 6", len(codes))
	}
	rounds, err := GamesByRoundCodesGA(codes)
	if err != nil {
		t.Fatalf("GamesByRoundCodesGA: %v", err)
	}
	if len(rounds) != 3 {
		t.Fatalf("GamesByRoundCodesGA len=%d, want 3 GA-only", len(rounds))
	}
	for _, r := range rounds {
		if !strings.HasPrefix(r.RoundCode, "GA") {
			t.Fatalf("DS leaked: %s", r.RoundCode)
		}
	}
}

func TestGameByRoundCodeGA_ReturnsNilForDS(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_by_code.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRounds(t, betoffer)

	gaCode := firstGACode(t, betoffer)
	r, err := GameByRoundCodeGA(gaCode)
	if err != nil || r == nil {
		t.Fatalf("expected GA round, got err=%v round=%v", err, r)
	}
	if r.RoundCode != gaCode {
		t.Fatalf("GameByRoundCodeGA got %s, want %s", r.RoundCode, gaCode)
	}

	dsCode := firstDSCode(t, betoffer)
	r2, err := GameByRoundCodeGA(dsCode)
	if err != nil {
		t.Fatalf("expected no error for DS code, got %v", err)
	}
	if r2 != nil {
		t.Fatalf("expected nil for DS code, got %v", r2)
	}
}

func TestResultsByRoundCodeGA_FiltersDS(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ga_results.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithResults(t, betoffer) // 3 DS finished + 2 GA finished, all with results

	// A finished GA round (has results) must return them.
	var gaFinished string
	if err := db.QueryRow(
		`SELECT RoundCode FROM GameRounds WHERE GameTypeId=? AND Status='F' AND RoundCode LIKE 'GA%' LIMIT 1`,
		betoffer,
	).Scan(&gaFinished); err != nil {
		t.Fatalf("find finished GA: %v", err)
	}
	res, err := ResultsByRoundCodeGA(gaFinished)
	if err != nil {
		t.Fatalf("ResultsByRoundCodeGA: %v", err)
	}
	if len(res) == 0 {
		t.Fatalf("ResultsByRoundCodeGA(%s) returned no results", gaFinished)
	}

	// A DS round must be filtered out (nil, nil) without touching the DB.
	dsCode := firstDSCode(t, betoffer)
	res2, err := ResultsByRoundCodeGA(dsCode)
	if err != nil {
		t.Fatalf("expected no error for DS code, got %v", err)
	}
	if res2 != nil {
		t.Fatalf("expected nil results for DS code, got %v", res2)
	}
}

func TestGamesAfterGameIDDS_SkipsGAInWindow(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ds_after.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRounds(t, betoffer) // DS in past, GA in future

	// Pivot on the oldest DS round so the future GA seeds fall AFTER it
	// (giving GA a real chance to leak if the filter is missing).
	pivot := firstDSCode(t, betoffer)
	rounds, err := GamesAfterGameIDDS(betoffer, pivot, 20)
	if err != nil {
		t.Fatalf("GamesAfterGameIDDS: %v", err)
	}
	for _, r := range rounds {
		if strings.HasPrefix(r.RoundCode, "GA") {
			t.Fatalf("GA leaked after pivot: %s", r.RoundCode)
		}
	}
}

func TestRecentResultsDS_FiltersGA(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ds_recent.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithResults(t, betoffer) // 3 DS finished + 2 GA finished

	rounds, resMap, err := RecentResultsDS(betoffer, 20)
	if err != nil {
		t.Fatalf("RecentResultsDS: %v", err)
	}
	if len(rounds) != 3 {
		t.Fatalf("RecentResultsDS len=%d, want 3 DS-only; rounds=%v", len(rounds), roundCodes(rounds))
	}
	for _, r := range rounds {
		if strings.HasPrefix(r.RoundCode, "GA") {
			t.Fatalf("GA leaked in results: %s", r.RoundCode)
		}
	}
	if resMap == nil {
		t.Fatal("RecentResultsDS: nil result map (want non-nil even when empty)")
	}
}

// TestGamesWindow_StillReturnsAll is the regression test ensuring that
// adding the *DS helpers did NOT alter the behaviour of GamesWindow.
// It must still return BOTH DS (numeric) and GA rounds.
func TestGamesWindow_StillReturnsAll(t *testing.T) {
	resetForTest(t)
	if err := Init(filepath.Join(t.TempDir(), "ds_regression.db")); err != nil {
		t.Fatalf("init: %v", err)
	}
	defer resetForTest(t)

	const betoffer = 541
	seedMixedRoundsWithFinishedGA(t, betoffer) // 3 DS F + 2 GA F + 3 GA O = 8

	rounds, err := GamesWindow(betoffer, 10, 10)
	if err != nil {
		t.Fatalf("GamesWindow: %v", err)
	}
	if len(rounds) != 8 {
		t.Fatalf("GamesWindow regressed: len=%d, want 8 (all rounds); rounds=%v", len(rounds), roundCodes(rounds))
	}
	hasNumeric, hasGA := false, false
	for _, r := range rounds {
		if strings.HasPrefix(r.RoundCode, "GA") {
			hasGA = true
		} else {
			hasNumeric = true
		}
	}
	if !hasGA || !hasNumeric {
		t.Fatalf("GamesWindow regressed: want both DS and GA; hasGA=%v hasNumeric=%v", hasGA, hasNumeric)
	}
}
